var chapterPlan = $("Select Next Chapter Plan").first().json;
var project = $("Load Active Project").first().json;

// genre is a string in DB, not array
var genre = project.genre || "";
if (Array.isArray(genre)) genre = genre.join(" ");

// tone is inside style_profile JSONB
var style = {};
try { style = typeof project.style_profile === "string" ? JSON.parse(project.style_profile) : (project.style_profile || {}); } catch(e) {}
var tone = style.tone || "";

var queryParts = [
  chapterPlan.title || "",
  (chapterPlan.plot_goals || []).join(" "),
  genre,
  tone
].filter(Boolean);

var retrievalQuery = queryParts.join(" ");
return [{ json: { retrieval_query: retrievalQuery, project_id: project.id, chapter_plan: chapterPlan, top_k: 12 } }];

var project = $("Load Active Project").first().json;
// Parse style_profile for tone
var style = {};
try { style = typeof project.style_profile === "string" ? JSON.parse(project.style_profile) : (project.style_profile || {}); } catch(e) {}
project.tone = style.tone || "";
// genre is string, not array
if (Array.isArray(project.genre)) project.genre = project.genre.join(", ");
const chapterPlan = $('Select Next Chapter Plan').first().json;
const projectConfig = $('Load Project Config').all();
const structuredCanon = $('Load Structured Canon').all();
const vectorContext = $('Retrieve Vector Context').all();
const job = $('Acquire Lock').first().json;
let styleGuide = {};
let hardRules = [];
let softRules = [];
let recentSummaries = [];
let systemSettings = {};
for (const item of projectConfig) {
  const j = item.json;
  if (Array.isArray(j)) {
  }
  if (j.narrative_perspective) styleGuide = j;
  if (j.rule_type === 'hard') hardRules.push(j);
  if (j.rule_type === 'soft') softRules.push(j);
  if (j.summary && j.sequence) recentSummaries.push(j);
  if (j.key && j.value) systemSettings[j.key] = j.value;
}
let characters = [];
let characterStates = [];
let locations = [];
let plotThreads = [];
let foreshadowing = [];
let timelineEvents = [];
for (const item of structuredCanon) {
  const j = item.json;
  if (j.role) characters.push(j);
  if (j.physical_state || j.emotional_state) characterStates.push(j);
  if (j.location_type) locations.push(j);
  if (j.thread_type) plotThreads.push(j);
  if (j.clue_text) foreshadowing.push(j);
  if (j.event_time_label) timelineEvents.push(j);
}
const writingBrief = {
  project: {
    id: project.id,
    title: project.name,
    genre: project.genre,
    tone: project.tone,
    style_profile: project.style_profile
  },
  chapter_plan: {
    id: chapterPlan.id,
    sequence: chapterPlan.sequence,
    title: chapterPlan.title,
    plot_goals: chapterPlan.plot_goals || [],
    summary: chapterPlan.summary || '',
    arc_stage: chapterPlan.arc_stage || '',
    major_events: chapterPlan.major_events || []
  },
  target_word_count: chapterPlan.target_word_count || project.daily_target_words || 3000,
  recent_summaries: recentSummaries.reverse(),
  active_characters: characters,
  character_states: characterStates,
  locations: locations,
  plot_threads: plotThreads,
  foreshadowing: foreshadowing,
  timeline_events: timelineEvents,
  canon_rules: { hard: hardRules, soft: softRules },
  style_guide: styleGuide,
  retrieved_context: vectorContext.map(v => ({
    id: v.json.id,
    source_type: v.json.source_type,
    title: v.json.title,
    content: v.json.content,
    similarity: v.json.similarity
  })),
  hard_constraints: hardRules.map(r => r.rule_text),
  quality_threshold: project.quality_threshold || 85,
  max_revise_count: project.max_revise_count || 2,
  auto_publish: project.auto_publish || false
};
return [{
  json: {
    job_id: job.id,
    project_id: project.id,
    chapter_plan_id: chapterPlan.id,
    writing_brief: writingBrief,
    auto_publish: project.auto_publish || false,
    quality_threshold: project.quality_threshold || 85,
    max_revise_count: project.max_revise_count || 2
  }
}];

const writingBrief = $('Build Writing Brief').first().json.writing_brief;
const chapter = $('Call Writer Service').first().json.data;
const chapterId = $('Save Chapter').first().json.id;
const versionId = $('Save Draft Version').first().json.id;
return [{
  json: {
    chapter_id: chapterId,
    version_id: versionId,
    chapter: chapter,
    writing_brief: writingBrief
  }
}];

const allReviews = $input.all();
const reviewData = [];
for (const item of allReviews) {
  try {
    const j = item.json;
    if (j.choices?.[0]?.message?.content) reviewData.push(JSON.parse(j.choices[0].message.content));
    else if (j.agent_name) reviewData.push(j);
    else if (j.data?.agent_name) reviewData.push(j.data);
    else reviewData.push({agent_name:"unknown",score:0,pass:false,blocking_issues:[{id:"PARSE_ERR",severity:"high",issue:"Unable to parse review output"}],minor_issues:[],recommendations:[]});
  } catch (e) {
    reviewData.push({agent_name:"parse_error",score:0,pass:false,blocking_issues:[{id:"PARSE_ERR",severity:"high",issue:"Failed to parse: "+e.message}],minor_issues:[],recommendations:[]});
  }
}
const safetyReview = reviewData.find(r => r.agent_name === "safety_reviewer");
const scores = reviewData.map(r => r.score).filter(s => typeof s === "number" && !isNaN(s));
const avgScore = scores.length > 0 ? Math.round((scores.reduce((a,b)=>a+b,0)/scores.length)*100)/100 : 0;
const allBlocking = [], allMinor = [], recsByAgent = {};
for (const r of reviewData) {
  (r.blocking_issues||[]).forEach(i => allBlocking.push({...i,agent_name:r.agent_name}));
  (r.minor_issues||[]).forEach(i => allMinor.push({...i,agent_name:r.agent_name}));
  if (r.recommendations?.length) recsByAgent[r.agent_name] = r.recommendations;
}
const hasBlocking = allBlocking.length > 0;
const safetyFailed = safetyReview?.pass === false;
const ctx = $("Build Writing Brief").first()?.json || $input.first().json;
const revCnt = ctx.revise_count ?? 0;
const maxRev = ctx.max_revise_count ?? 2;
const qThresh = ctx.quality_threshold ?? 85;
let decision, finalScore;
if (safetyFailed) { decision = "needs_human_review"; }
else if (revCnt >= maxRev && hasBlocking) { decision = "needs_human_review"; }
else if (hasBlocking) { decision = "revise"; }
else if (avgScore >= qThresh) { decision = "publish_ready"; }
else { decision = "revise"; }
if (safetyFailed) finalScore = Math.min(avgScore, 40);
else if (hasBlocking) finalScore = Math.min(avgScore, 74);
else finalScore = avgScore;
finalScore = Math.round(finalScore * 100) / 100;
const prep = $("Prepare Review Input").first().json;
return [{ json: {
  chapter_id: prep.chapter_id, version_id: prep.version_id,
  average_score: avgScore, final_score: finalScore,
  decision: decision, publish_allowed: decision === "publish_ready",
  safety_pass: !safetyFailed, has_blocking: hasBlocking,
  all_pass: reviewData.every(r => r.pass !== false),
  blocking_issues: allBlocking, minor_issues: allMinor,
  must_fix: allBlocking.filter(i => i.severity === "high" || safetyFailed),
  recommendations: recsByAgent, reviews: reviewData,
  agent_count: reviewData.length, blocking_count: allBlocking.length, minor_count: allMinor.length
}}];

var writerResp = $("Call Writer Service").first().json;
var chData = writerResp.data || writerResp;
var proj = $("Load Active Project").first().json;
var plan = $("Select Next Chapter Plan").first().json;

var title = chData.title || plan.title || "Untitled";
var content = chData.body_markdown || chData.content || "";
var wordCount = chData.word_count || content.length;
var summary = chData.summary || "";
var date = new Date().toISOString().split("T")[0];
var seq = plan.sequence || 1;

var md = "# " + title + "\n\n";
md += "> 项目: " + (proj.name || "") + " | 章节: " + seq + " | 日期: " + date + " | 字数: " + wordCount + "\n\n";
if (summary) md += "> " + summary + "\n\n";
md += content + "\n\n";
md += "---\n";
md += "*Generated by AI Novel Factory*\n";

var slug = (proj.name || "novel").replace(/[^a-zA-Z0-9\u4e00-\u9fff]+/g, "-").toLowerCase();
var filename = "/data/paper/" + slug + "-ch" + String(seq).padStart(3,"0") + ".md";

return [{ json: { filename: filename, content: md, title: title, sequence: seq, word_count: wordCount } }];

var fs = require("fs");
var path = require("path");
var data = $input.first().json;

var dir = "/data/paper";
try { fs.mkdirSync(dir, { recursive: true }); } catch(e) {}

fs.writeFileSync(data.filename, data.content, "utf8");
console.log("Saved: " + data.filename);

return [{ json: { saved: true, filename: data.filename, title: data.title, sequence: data.sequence } }];

const error = $input.first().json;
return [{
  json: {
    error: error.message || 'Unknown workflow error',
    node: error.node || 'unknown',
    timestamp: new Date().toISOString(),
    job_id: $('Build Writing Brief').first()?.json?.job_id || null
  }
}];
